// 设置 AWS 配置和 SQL 查询
const awsConfig = {
  region: 'us-west-2',
  accessKeyId: 'AKIAQQJLCWBOOKC7J6ZI',
  secretAccessKey: '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'
};

const athenaConfig = {
  database: 'gmp',
  outputLocation: 's3://aws-athena-query-results-us-west-2-034986963036/',
