};

// 你的具体 SQL 查询
const sqlQuery = `SELECT id, uid, merchant_id, game_id, game_code, result, currency, ROUND(CAST(amount AS DOUBLE), 2) AS amount, ROUND(CAST(pay_out AS DOUBLE), 2) AS pay_out, multiplier, balance, detail, DATE_FORMAT(FROM_UNIXTIME(created_at / 1000), '%Y-%m-%d %H:%i:%s') AS created_at, DATE_FORMAT(FROM_UNIXTIME(updated_at / 1000), '%Y-%m-%d %H:%i:%s') AS updated_at FROM game_records WHERE provider = 'gp' AND merchant = '1737978166' AND id in ('1976423513265401856','1976422629802373120','1976437176340557824') AND updated_at BETWEEN TO_UNIXTIME(PARSE_DATETIME('2025-10-01 00:00:00', 'yyyy-MM-dd HH:mm:ss')) * 1000 AND TO_UNIXTIME(PARSE_DATETIME('2025-10-30 23:59:59', 'yyyy-MM-dd HH:mm:ss')) * 1000`;

return {
  json: {
    awsConfig,
    athenaConfig,
    sqlQuery,
    queryId: null,
    status: 'ready'
  }
};

// 导入 AWS SDK 并启动 Athena 查询
const AWS = require('aws-sdk');

// 配置 AWS
const { awsConfig, athenaConfig, sqlQuery } = $json;

AWS.config.update({
  region: awsConfig.region,
  accessKeyId: awsConfig.accessKeyId,
  secretAccessKey: awsConfig.secretAccessKey
});

const athena = new AWS.Athena();

// 启动查询执行
const params = {
  QueryString: sqlQuery,
  QueryExecutionContext: {
    Database: athenaConfig.database
  },
  ResultConfiguration: {
    OutputLocation: athenaConfig.outputLocation
  },
  WorkGroup: athenaConfig.workGroup
};

try {
  console.log('Starting Athena query...');
  const result = await athena.startQueryExecution(params).promise();

  console.log('Query started with ID:', result.QueryExecutionId);

  return {
    json: {
      queryId: result.QueryExecutionId,
      status: 'started',
      message: '查询已启动，正在执行中...',
      timestamp: new Date().toISOString(),
      sqlQuery: sqlQuery.substring(0, 100) + '...' // 截断显示
    }
  };
} catch (error) {
  console.error('Error starting query:', error);
  return {
    json: {
      success: false,
      error: error.message,
      status: 'failed',
      timestamp: new Date().toISOString()
    }
  };
}

// 检查查询状态
const AWS = require('aws-sdk');
const { queryId, awsConfig } = $json;

if (!queryId) {
  return {
    json: {
      success: false,
      error: 'No query ID available',
      status: 'failed'
    }
  };
}

// 配置 AWS
AWS.config.update({
  region: awsConfig.region,
  accessKeyId: awsConfig.accessKeyId,
  secretAccessKey: awsConfig.secretAccessKey
});

const athena = new AWS.Athena();

// 获取查询执行状态
try {
  const result = await athena.getQueryExecution({ QueryExecutionId: queryId }).promise();
  const execution = result.QueryExecution;

  const status = execution.Status.State;
  const statusChangeReason = execution.Status.StateChangeReason || '';

  console.log(`Query ${queryId} status: ${status}`);

  return {
    json: {
      queryId,
      status: status.toLowerCase(),
      statusChangeReason,
      dataScannedInBytes: execution.Statistics?.DataScannedInBytes,
      engineExecutionTimeInMillis: execution.Statistics?.EngineExecutionTimeInMillis,
      timestamp: new Date().toISOString()
    }
  };
} catch (error) {
  console.error('Error checking query status:', error);
  return {
    json: {
      queryId,
      success: false,
      error: error.message,
      status: 'error'
    }
  };
}

// 获取查询结果
const AWS = require('aws-sdk');
const { queryId, awsConfig } = $json;

// 配置 AWS
AWS.config.update({
  region: awsConfig.region,
  accessKeyId: awsConfig.accessKeyId,
  secretAccessKey: awsConfig.secretAccessKey
});

const athena = new AWS.Athena();

try {
  // 获取查询结果
  const resultParams = {
    QueryExecutionId: queryId,
    MaxResults: 1000 // 限制结果数量
  };

  const result = await athena.getQueryResults(resultParams).promise();

  // 处理结果
  const columns = result.ResultSet.ResultSetMetadata.ColumnInfo.map(col => col.Name);
  const rows = result.ResultSet.Rows.slice(1).map(row => { // 跳过标题行
    const rowData = {};
    row.Data.forEach((cell, index) => {
      rowData[columns[index]] = cell.VarCharValue || null;
    });
    return rowData;
  });

  console.log(`Query completed with ${rows.length} rows`);

  return {
    json: {
      success: true,
      queryId,
      status: 'completed',
      rowCount: rows.length,
      columns,
      data: rows,
      message: `查询成功！返回 ${rows.length} 条记录`,
      timestamp: new Date().toISOString()
    }
  };
} catch (error) {
  console.error('Error getting query results:', error);
  return {
    json: {
      success: false,
      queryId,
      error: error.message,
      status: 'failed',
      timestamp: new Date().toISOString()
    }
  };
}

// 超时处理
return {
  json: {
    success: false,
    queryId: $json.queryId,
    status: 'timeout',
    error: '查询超时',
    message: '查询执行超过5分钟，请检查查询条件或联系管理员',
    timestamp: new Date().toISOString()
  }
};

// 最终结果处理
const data = $json;

if (data.success && data.data) {
  // 成功结果
  return {
    json: {
      success: true,
      message: data.message || '查询执行成功',
      queryId: data.queryId,
      rowCount: data.rowCount,
      columns: data.columns,
      data: data.data,
      executionTime: data.executionTime || 'N/A',
      timestamp: data.timestamp
    }
  };
} else {
  // 失败结果
  return {
    json: {
      success: false,
      message: data.message || data.error || '查询执行失败',
      queryId: data.queryId,
      error: data.error,
      status: data.status,
      timestamp: data.timestamp
    }
  };
}
